import{_ as o,C as r,o as i,c as l,ag as e,E as s,w as d,a as n}from"./chunks/framework.BZohXCq9.js";const P=JSON.parse('{"title":"Cómo Se Ve — Diseño","description":"Elige la paleta de colores y tema visual de tu página","frontmatter":{"title":"Cómo Se Ve — Diseño","description":"Elige la paleta de colores y tema visual de tu página"},"headers":[],"relativePath":"studio/seccion-diseno.md","filePath":"studio/seccion-diseno.md"}'),c={name:"studio/seccion-diseno.md"};function u(p,a,g,h,m,b){const t=r("Note");return i(),l("div",null,[a[1]||(a[1]=e('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p><strong>Cómo Se Ve</strong> es el tab de tu panel donde eliges el aspecto visual de tu página. Aquí seleccionas la paleta de colores que define toda la apariencia de tu landing: botones, fondos, textos y acentos.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Cómo Se Ve</strong> (tercer ícono en el menú lateral, 🎨)</p><p>La pantalla se divide en dos partes:</p><ul><li><strong>Izquierda (principal):</strong> Grid de paletas de color disponibles, agrupadas por categoría</li><li><strong>Derecha (lateral):</strong> Paleta personalizada (solo plan Visión)</li></ul><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="paletas-de-color-predisenadas" tabindex="-1">Paletas de color prediseñadas <a class="header-anchor" href="#paletas-de-color-predisenadas" aria-label="Permalink to &quot;Paletas de color prediseñadas&quot;">​</a></h3><p>Hay <strong>30+ paletas</strong> organizadas por categoría de negocio:</p><table tabindex="0"><thead><tr><th>Categoría</th><th>Paletas incluidas</th><th>Ideal para</th></tr></thead><tbody><tr><td><strong>Clean</strong></td><td>Default, Harvest, Ocean, Cashmere</td><td>Negocio general, minimalista</td></tr><tr><td><strong>Fresh</strong></td><td>Olive, Retro, Bubblegum</td><td>Negocios creativos, juveniles</td></tr><tr><td><strong>Bold</strong></td><td>Autumn</td><td>Negocios llamativos</td></tr><tr><td><strong>Dark</strong></td><td>Moon</td><td>Negocios premium, elegantes</td></tr><tr><td><strong>Comida</strong></td><td>Sabor Tradicional, Fuego Urbano, Parrilla Moderna, Casa Latina</td><td>Restaurantes, areperas, comida</td></tr><tr><td><strong>Dulces</strong></td><td>Rosa Vainilla, Pistacho Suave, Cielo Dulce, Chocolate Caramelo</td><td>Pastelerías, dulcerías</td></tr><tr><td><strong>Salud</strong></td><td>Azul Confianza, Verde Calma</td><td>Clínicas, consultorios</td></tr><tr><td><strong>Autoridad</strong></td><td>Azul Profesional, Ejecutivo Oscuro, Prestigio Clásico</td><td>Abogados, contadores, consultores</td></tr><tr><td><strong>Oficios</strong></td><td>Industrial Pro, Negro Impacto, Metal Urbano</td><td>Ferreterías, talleres</td></tr><tr><td><strong>Belleza</strong></td><td>Nude Elegante, Rosa Studio</td><td>Peluquerías, salones, spas</td></tr><tr><td><strong>Fitness</strong></td><td>Barber Clásico, Fuerza Roja, Verde Potencia, Azul Eléctrico</td><td>Gimnasios, entrenadores</td></tr><tr><td><strong>Educación</strong></td><td>Azul Académico, Verde Progreso, Claro Simple</td><td>Academias, tutores</td></tr></tbody></table><p>Cada paleta muestra:</p><ul><li>Nombre de la paleta</li><li>Franja de 4 colores (primario, variantes claras y oscuras)</li><li>Indicador de selección (borde azul + checkmark)</li></ul><h3 id="seleccionar-una-paleta" tabindex="-1">Seleccionar una paleta <a class="header-anchor" href="#seleccionar-una-paleta" aria-label="Permalink to &quot;Seleccionar una paleta&quot;">​</a></h3><p>Dale clic a cualquier paleta → se aplica inmediatamente a tu landing. Los 4 colores de la paleta definen las variables CSS <code>--brand-50</code>, <code>--brand-500</code>, <code>--brand-600</code>, <code>--brand-700</code> que controlan toda la apariencia.</p><h3 id="paleta-personalizada-solo-vision" tabindex="-1">Paleta personalizada (solo Visión) <a class="header-anchor" href="#paleta-personalizada-solo-vision" aria-label="Permalink to &quot;Paleta personalizada (solo Visión)&quot;">​</a></h3><p>En el panel derecho, los usuarios del plan <strong>Visión</strong> pueden crear una paleta completamente personalizada:</p><ol><li>Introduce un <strong>color primario</strong> en formato hexadecimal (ej: <code>#FF6B35</code>)</li><li>Dale clic a <strong>&quot;Aplicar Paleta Custom&quot;</strong></li><li>El sistema genera automáticamente las 4 variantes (50, 500, 600, 700)</li></ol><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite cambiar fuentes tipográficas — se usa la fuente del sistema</li><li>No permite editar CSS directamente</li><li>No tiene modo oscuro/claro (la landing siempre usa fondo blanco)</li><li>No permite colores distintos por sección</li><li>No guarda historial de paletas anteriores</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>Paletas disponibles</td><td>10</td><td>17</td><td>17</td></tr><tr><td>Paleta personalizada</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Categorías visibles</td><td>Limitadas</td><td>Todas</td><td>Todas</td></tr></tbody></table>',21)),s(t,null,{default:d(()=>[...a[0]||(a[0]=[n(" En el plan **Oportunidad**, no todas las categorías de paletas están disponibles. Las paletas de categorías como Dark, Autoridad o Fitness pueden requerir plan Crecimiento o superior. ",-1)])]),_:1}),a[2]||(a[2]=e('<h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-gym-iron-power-en-puerto-la-cruz" tabindex="-1">Caso: Gym &quot;Iron Power&quot; en Puerto La Cruz <a class="header-anchor" href="#caso-gym-iron-power-en-puerto-la-cruz" aria-label="Permalink to &quot;Caso: Gym &quot;Iron Power&quot; en Puerto La Cruz&quot;">​</a></h3><p>Diego tiene un gimnasio. Va a <strong>Cómo Se Ve</strong> y ve las paletas organizadas por categoría:</p><ol><li>Baja hasta la categoría <strong>Fitness</strong></li><li>Ve las opciones: Fuerza Roja, Verde Potencia, Azul Eléctrico</li><li>Dale clic a <strong>&quot;Fuerza Roja&quot;</strong> — su landing cambia a tonos rojos intensos</li><li>Prueba <strong>&quot;Azul Eléctrico&quot;</strong> — le gusta más</li><li>Cierra el panel → su página queda con la paleta Azul Eléctrico</li></ol><p>Si Diego tuviera el plan <strong>Visión</strong>, podría ir al panel derecho, escribir <code>#FF4500</code> (naranja intenso) y crear una paleta propia que nadie más tiene.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/paletas-de-color.html">Paletas de color</a> — Lista completa de las 30+ paletas</li><li><a href="/studio/seccion-visual.html">Visual — Variantes y efectos</a> — Cambia la estructura de cada sección</li><li><a href="/studio/panel-administracion.html">Panel de administración</a> — Los 7 tabs del panel</li></ul>',7))])}const C=o(c,[["render",u]]);export{P as __pageData,C as default};
